class Solution:
    def getWinner(self, arr, k):
        champion = arr[0]
        streak = 0
        for i in range(1, len(arr)):
            if arr[i] > champion:
                champion = arr[i]
                streak = 1
            else:
                streak += 1
            if streak >= k:
                return champion
        return champion

