var getWinner = function(arr, k) {
    let champion = arr[0];
    let streak = 0;
    for (let i = 1; i < arr.length; i++) {
        if (arr[i] > champion) {
            champion = arr[i];
            streak = 1;
        } else {
            streak += 1;
        }
        if (streak >= k) return champion;
    }
    return champion;
};
